var countOrders = function(n) {
    const MOD = 1000000007n;
    let ans = 1n;
    for (let k = 1n; k <= BigInt(n); k++) {
        ans = (ans * (2n * k - 1n)) % MOD;
        ans = (ans * k) % MOD;
    }
    return Number(ans);
};
